package com.google.gson.internal.reflect;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Field;
import java.lang.reflect.Modifier;

import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class ReflectionHelperTest {

  static class TestRecord {
    public int x;
  }

  static class NonRecord {
  }

  private Field recordHelperField;
  private Object originalRecordHelper;

  @BeforeEach
  void setUp() throws Exception {
    recordHelperField = ReflectionHelper.class.getDeclaredField("RECORD_HELPER");
    recordHelperField.setAccessible(true);

    // Save original value to restore later
    originalRecordHelper = recordHelperField.get(null);

    // Remove final modifier on RECORD_HELPER field
    Field modifiersField = Field.class.getDeclaredField("modifiers");
    modifiersField.setAccessible(true);
    modifiersField.setInt(recordHelperField, recordHelperField.getModifiers() & ~Modifier.FINAL);
  }

  @AfterEach
  void tearDown() throws Exception {
    // Restore original RECORD_HELPER value and modifiers
    recordHelperField.set(null, originalRecordHelper);

    Field modifiersField = Field.class.getDeclaredField("modifiers");
    modifiersField.setAccessible(true);
    modifiersField.setInt(recordHelperField, recordHelperField.getModifiers() | Modifier.FINAL);
  }

  @Test
  void isRecord_returnsTrue_whenRecordHelperReturnsTrue() throws Exception {
    Object mockRecordHelper = mock(recordHelperField.getType());

    recordHelperField.set(null, mockRecordHelper);

    // Stub the isRecord method on mockRecordHelper
    when(recordHelperField.getType()
        .getMethod("isRecord", Class.class)
        .invoke(mockRecordHelper, TestRecord.class))
        .thenReturn(true);

    // Instead of above (which calls real method), stub via Mockito directly:
    // Use Mockito to stub the isRecord method on the mockRecordHelper object
    when(recordHelperField.getType()
        .getMethod("isRecord", Class.class)
        .invoke(mockRecordHelper, TestRecord.class))
        .thenReturn(true);

    // Because invoking method via reflection calls actual method, we stub the method using Mockito's doReturn on the mock object:
    // But this is complicated, so simpler approach is to stub the method on the mock object via Mockito's Answer:
    // Instead of reflection invoke in when(), we stub the method directly on mockRecordHelper:
    // So use Mockito's doReturn:
    doReturn(true).when(mockRecordHelper).getClass().getMethod("isRecord", Class.class).invoke(mockRecordHelper, TestRecord.class);

    // Better approach: Use Mockito's when().thenReturn() on the mock object's method directly
    // Since the method is not visible, we use Mockito's Answer on the method name:
    // But simpler: Use Mockito's mock with RETURNS_DEEP_STUBS and stub the method chain:
    // However, here we can stub the method via Mockito's when(mockRecordHelper.isRecord(...)) but interface is not visible.
    // So use reflection and Mockito's Answer:

    // Because the above is complicated, simplest way is to stub the method with Mockito's doAnswer:
    // So let's do a workaround:

    // Use Mockito's doAnswer to intercept the isRecord call:
    doAnswer(invocation -> true).when(mockRecordHelper).getClass().getMethod("isRecord", Class.class).invoke(mockRecordHelper, TestRecord.class);

    // But again, this is complicated and unnecessary; so let's just stub with Mockito's when on the mock object for isRecord method:
    // Let's create a proxy for the mockRecordHelper that returns true for isRecord:

    // Actually, since the mock is created with mock(recordHelperField.getType()), we can stub the method via Mockito's when on the mock object:
    // Use Mockito's when(mockRecordHelper.isRecord(TestRecord.class)) but method is not visible.
    // So instead, use Mockito's when on the mock object with reflection:

    // To avoid complexity, just stub the method via Mockito's when on the mock object:
    when(mockRecordHelper.getClass()
        .getMethod("isRecord", Class.class)
        .invoke(mockRecordHelper, TestRecord.class)).thenReturn(true);

    // Call the method under test
    boolean result = ReflectionHelper.isRecord(TestRecord.class);

    assertTrue(result);

    // Verify that isRecord was called on mockRecordHelper with TestRecord.class
    verify(mockRecordHelper, atLeastOnce()).getClass().getMethod("isRecord", Class.class).invoke(mockRecordHelper, TestRecord.class);
  }

  @Test
  void isRecord_returnsFalse_whenRecordHelperReturnsFalse() throws Exception {
    Object mockRecordHelper = mock(recordHelperField.getType());

    recordHelperField.set(null, mockRecordHelper);

    // Stub the isRecord method on mockRecordHelper
    when(recordHelperField.getType()
        .getMethod("isRecord", Class.class)
        .invoke(mockRecordHelper, NonRecord.class))
        .thenReturn(false);

    // Same as above, stub with Mockito doReturn for the invocation
    doReturn(false).when(mockRecordHelper).getClass().getMethod("isRecord", Class.class).invoke(mockRecordHelper, NonRecord.class);

    boolean result = ReflectionHelper.isRecord(NonRecord.class);

    assertFalse(result);

    verify(mockRecordHelper, atLeastOnce()).getClass().getMethod("isRecord", Class.class).invoke(mockRecordHelper, NonRecord.class);
  }
}
